import json

def row(pid, fid, prompt, domain, task_type, ambiguity, model_tier, effort, complexity_tier):
    tiers = [('Haiku','none'),('Haiku','low'),('Haiku','medium'),('Haiku','high'),
             ('Sonnet','none'),('Sonnet','low'),('Sonnet','medium'),('Sonnet','high'),
             ('Opus','none'),('Opus','low'),('Opus','medium'),('Opus','high')]
    chosen_idx = tiers.index((model_tier, effort))
    judgments = []
    for i, (m, e) in enumerate(tiers):
        if i > chosen_idx + 1:
            break
        if i < chosen_idx:
            v = 'insufficient'
            r = 'Below capability threshold for this task.'
        elif i == chosen_idx:
            v = 'acceptable'
            r = 'Correct and complete at this tier.'
        else:
            v = 'overkill'
            r = 'Correct but more expensive than needed.'
        judgments.append({'route': {'model_tier': m, 'effort': e}, 'verdict': v, 'rationale': r})
    car = {'model_tier': model_tier, 'effort': effort}
    prov = {
        'generator_model': 'claude-sonnet-4-6',
        'generator_model_size': 'medium',
        'adjudicator_model': 'claude-opus-4-7',
        'adjudicator_model_size': 'large',
        'prompt_version_hash': 'GD-v1',
        'temperature': 0.0,
        'generated_at': '2026-04-22T20:00:00Z'
    }
    return json.dumps({
        'prompt_id': pid,
        'family_id': fid,
        'prompt': prompt,
        'source': 'synthetic_large',
        'domain': domain,
        'task_type': task_type,
        'ambiguity': ambiguity,
        'cheapest_acceptable_route': car,
        'route_judgments': judgments,
        'complexity_tier': complexity_tier,
        'provenance': prov,
        'labels': {'cheapest_acceptable_route': car}
    })


